    private suspend fun extractSharedContent(intent: Intent): SharedContent {
        val uris = LinkedHashSet<Uri>()
        val texts = ArrayList<String>()

        fun addClipData(cd: ClipData?) {
            if (cd == null) return
            for (i in 0 until cd.itemCount) {
                val item = cd.getItemAt(i)
                item.uri?.let { uris.add(it) }
                item.text?.toString()?.let { if (it.isNotBlank()) texts.add(it) }
                item.intent?.let {
                    it.data?.let { d -> uris.add(d) }
                    it.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)?.let { s -> uris.add(s) }
                    it.getStringExtra(Intent.EXTRA_TEXT)?.let { t -> if (t.isNotBlank()) texts.add(t) }
                }
            }
        }

        addClipData(intent.clipData)

        intent.getStringExtra(Intent.EXTRA_TEXT)?.let { if (it.isNotBlank()) texts.add(it) }
        intent.getCharSequenceExtra(Intent.EXTRA_TEXT)?.toString()?.let { if (it.isNotBlank()) texts.add(it) }

        when (intent.action) {
            Intent.ACTION_SEND -> {
                val stream = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                if (stream != null) uris.add(stream)
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                val list = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
                if (list != null) uris.addAll(list)
            }
        }

        val normalizedTexts = texts
            .flatMap { splitMaybeMultipleLinks(it) }
            .map { it.trim() }
            .filter { it.isNotBlank() }
            .distinct()

        val urls = normalizedTexts
            .mapNotNull { toValidUrlOrNull(it) }
            .distinct()

        val nonUrlText = normalizedTexts
            .filter { toValidUrlOrNull(it) == null }
            .distinct()

        val images = ArrayList<SharedImage>()

        for (uri in uris) {
            val type = withContext(Dispatchers.IO) { contentResolver.getType(uri) }
            val looksLikeImage = type?.startsWith("image/") == true || uri.toString().contains("image", ignoreCase = true)
            if (!looksLikeImage) continue

            val meta = withContext(Dispatchers.IO) { queryMeta(uri) }
            val localCopy = withContext(Dispatchers.IO) { copyToCacheIfPossible(uri, meta.displayName) }
            val sizeBytes = localCopy?.length() ?: meta.sizeBytes
            val dims = withContext(Dispatchers.IO) { decodeImageBounds(uri) }

            images.add(
                SharedImage(
                    uri = uri,
                    localCacheFile = localCopy,
                    mimeType = type,
                    displayName = meta.displayName,
                    sizeBytes = sizeBytes,
                    width = dims.first,
                    height = dims.second
                )
            )
        }

        return SharedContent(
            urls = urls,
            images = images,
            rawText = nonUrlText
        )
    }

