    private fun toValidUrlOrNull(s: String): String? {
        val t = s.trim()
        if (t.isBlank()) return null

        if (URLUtil.isValidUrl(t)) return t

        val withScheme = when {
            t.startsWith("www.", ignoreCase = true) -> "https://$t"
            else -> null
        }
        if (withScheme != null && URLUtil.isValidUrl(withScheme)) return withScheme

        return null
    }

    private fun splitMaybeMultipleLinks(text: String): List<String> {
        val t = text.trim()
        if (t.isBlank()) return emptyList()
        return t.split('\n', ' ', '\t', ',', ';')
            .map { it.trim() }
            .filter { it.isNotBlank() }
    }

    private data class UriMeta(val displayName: String?, val sizeBytes: Long?)

    private fun queryMeta(uri: Uri): UriMeta {
        var name: String? = null
        var size: Long? = null
        val projection = arrayOf(OpenableColumns.DISPLAY_NAME, OpenableColumns.SIZE)
        contentResolver.query(uri, projection, null, null, null)?.use { c ->
            if (c.moveToFirst()) {
                val nameIdx = c.getColumnIndex(OpenableColumns.DISPLAY_NAME)
                val sizeIdx = c.getColumnIndex(OpenableColumns.SIZE)
                if (nameIdx >= 0) name = c.getString(nameIdx)
                if (sizeIdx >= 0 && !c.isNull(sizeIdx)) size = c.getLong(sizeIdx)
            }
        }
        return UriMeta(name, size)
    }

    private fun copyToCacheIfPossible(uri: Uri, displayName: String?): File? {
        return try {
            val safeName = (displayName ?: "shared_${System.currentTimeMillis()}").replace(Regex("[^a-zA-Z0-9._-]"), "_")
            val outFile = File(cacheDir, safeName)
            contentResolver.openInputStream(uri)?.use { input ->
                FileOutputStream(outFile).use { output ->
                    input.copyTo(output)
                }
            } ?: return null
            outFile
        } catch (_: Throwable) {
            null
        }
    }

    private fun decodeImageBounds(uri: Uri): Pair<Int?, Int?> {
        return try {
            val opts = BitmapFactory.Options().apply { inJustDecodeBounds = true }
            contentResolver.openInputStream(uri)?.use { input ->
                BitmapFactory.decodeStream(input, null, opts)
            }
            val w = if (opts.outWidth > 0) opts.outWidth else null
            val h = if (opts.outHeight > 0) opts.outHeight else null
            Pair(w, h)
        } catch (_: Throwable) {
            Pair(null, null)
        }
    }

    private fun isPermissionPossiblyRequired(intent: Intent): Boolean {
        val stream = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        return stream != null && stream.scheme == "content"
    }
